data.content:
MSTest **does not have** `Assert.IsGreaterThan` or `Assert.IsInRange` — those don't exist. Here's what you actually use:

| Need | MSTest Approach |
|---|---|
| Greater than | `Assert.IsTrue(val > x)` |
| Range check | `Assert.IsTrue(val >= lo && val <= hi)` |
| Exact value | `Assert.AreEqual(expected, actual, delta)` |
| Exception | `Assert.ThrowsException<T>(action)` |

For `double` equality, always use the 3-arg overload with a tolerance: `Assert.AreEqual(expected, actual, 0.001)`.

Here's a complete test class:

```csharp
using Contoso.Scoring;

namespace Contoso.Scoring.Tests;

[TestClass]
public class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calc = new();

    // ── CalculatePercentage ──

    [TestMethod]
    public void CalculatePercentage_PerfectScore_Returns100()
    {
        Assert.AreEqual(100.0, _calc.CalculatePercentage(10, 10), 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroCorrect_ReturnsZero()
    {
        Assert.AreEqual(0.0, _calc.CalculatePercentage(0, 10), 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_Partial_ReturnsExpected()
    {
        double result = _calc.CalculatePercentage(7, 10);
        Assert.AreEqual(70.0, result, 0.001);
        // Range check: percentage must be in [0, 100]
        Assert.IsTrue(result >= 0.0 && result <= 100.0,
            $"Percentage {result} is out of [0, 100]");
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(11, 10));
    }

    // ── GetGrade boundary tests ──

    [DataTestMethod]
    [DataRow(90.0, "A")]
    [DataRow(100.0, "A")]
    [DataRow(89.999, "B")]   // just below A boundary
    [DataRow(80.0, "B")]
    [DataRow(79.999, "C")]   // just below B boundary
    [DataRow(70.0, "C")]
    [DataRow(69.999, "D")]   // just below C boundary
    [DataRow(60.0, "D")]
    [DataRow(59.999, "F")]   // just below D boundary
    [DataRow(0.0, "F")]
    public void GetGrade_AtBoundaries_ReturnsCorrectGrade(
        double percentage, string expected)
    {
        Assert.AreEqual(expected, _calc.GetGrade(percentage));
    }

    // ── NormalizeScore ──

    [TestMethod]
    public void NormalizeScore_HalfOfMax_Returns50()
    {
        Assert.AreEqual(50.0, _calc.NormalizeScore(25, 50), 0.001);
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_ClampedTo100()
    {
        double result = _calc.NormalizeScore(120, 100);
        Assert.AreEqual(100.0, result, 0.001);
        // Verify it never exceeds 100
        Assert.IsTrue(result <= 100.0,
            $"Normalized score {result} should not exceed 100");
    }

    [TestMethod]
    public void NormalizeScore_Zero_ReturnsZero()
    {
        Assert.AreEqual(0.0, _calc.NormalizeScore(0, 50), 0.001);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(-1, 50));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(10, 0));
    }
}
```

**Key patterns used:**

- **`Assert.AreEqual(expected, actual, 0.001)`** — floating-point equality with tolerance (the `delta` parameter)
- **`Assert.IsTrue(val >= lo && val <= hi)`** — range checking (no built-in range assert)
- **`Assert.ThrowsException<T>`** — verifying guard clauses throw
- **`[DataTestMethod]` + `[DataRow]`** — parameterized tests hitting each grade boundary from both sides
